                errors.append(f"  Row {i}: missing {field}")

        if row['decision'] == 'emit_edge':
            required_emit = ['evidence_kind', 'edge_type', 'evidence_snippet', 'evidence_section', 'confidence_tier']
            for field in required_emit:
                if field not in row:
                    errors.append(f"  Row {i}: emit_edge missing {field}")
            # Check types
            if not isinstance(row['confidence_tier'], int):
                errors.append(f"  Row {i}: confidence_tier must be int, got {type(row['confidence_tier'])}")
        elif row['decision'] == 'reject_just_mention':
            if 'reason' not in row:
                errors.append(f"  Row {i}: reject missing reason")

    if errors:
        print(f"✗ {path.name} - VALIDATION ERRORS:")
        for err in errors[:3]:
            print(err)
    else:
        print(f"✓ {path.name} - Valid ({len(rows)} rows)")

